// Client — Firebase Auth
import { initializeApp } from 'firebase/app';
import { getAuth, signInWithPopup, GoogleAuthProvider, onAuthStateChanged } from 'firebase/auth';

const app = initializeApp({ apiKey: '...', authDomain: '...', projectId: '...' });
const auth = getAuth(app);

// Google sign-in
async function signInWithGoogle() {
  const provider = new GoogleAuthProvider();
  const result = await signInWithPopup(auth, provider);
  const idToken = await result.user.getIdToken();
  // Send idToken to backend for verification
  await fetch('/api/auth/login', { method: 'POST', headers: { Authorization: `Bearer ${idToken}` } });
}

// Auth state listener
onAuthStateChanged(auth, (user) => {
  if (user) { console.log('Logged in:', user.email); }
  else { console.log('Logged out'); }
});

// Server — verify token
import { getAuth } from 'firebase-admin/auth';
async function verifyToken(idToken: string) {
  const decoded = await getAuth().verifyIdToken(idToken);
  return { uid: decoded.uid, email: decoded.email };
}

// Permission definitions
const PERMISSIONS = {
  admin: ['read', 'write', 'delete', 'manage_users', 'manage_settings'],
  editor: ['read', 'write', 'delete'],
  viewer: ['read'],
} as const;

type Role = keyof typeof PERMISSIONS;
type Permission = (typeof PERMISSIONS)[Role][number];

function hasPermission(userRole: Role, required: Permission): boolean {
  return (PERMISSIONS[userRole] as readonly string[]).includes(required);
}

// Middleware
function requirePermission(permission: Permission) {
  return (req: Request) => {
    const user = getAuthUser(req);
    if (!user) throw new UnauthorizedError();
    if (!hasPermission(user.role, permission)) throw new ForbiddenError();
  };
}

// Usage in API route
export async function DELETE(req: Request) {
  requirePermission('delete')(req);
  // ... delete logic
}

import { cookies } from 'next/headers';
import { randomUUID } from 'crypto';

// Session store (use Redis in production)
const sessions = new Map<string, { userId: string; expiresAt: number }>();

async function createSession(userId: string): Promise<string> {
  const sessionId = randomUUID();
  const expiresAt = Date.now() + 7 * 24 * 60 * 60 * 1000; // 7 days
  sessions.set(sessionId, { userId, expiresAt });

  cookies().set('session', sessionId, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 7 * 24 * 60 * 60,
    path: '/',
  });
  return sessionId;
}

function getSession(): { userId: string } | null {
  const sessionId = cookies().get('session')?.value;
  if (!sessionId) return null;
  const session = sessions.get(sessionId);
  if (!session || session.expiresAt < Date.now()) {
    sessions.delete(sessionId!);
    return null;
  }
  return { userId: session.userId };
}

// Step 1: Generate auth URL
function getAuthUrl(provider: 'google' | 'github') {
  const state = randomUUID(); // CSRF protection
  const params = new URLSearchParams({
    client_id: PROVIDERS[provider].clientId,
    redirect_uri: `${BASE_URL}/api/auth/callback/${provider}`,
    response_type: 'code',
    scope: PROVIDERS[provider].scope,
    state,
  });
  return `${PROVIDERS[provider].authUrl}?${params}`;
}

// Step 2: Handle callback
export async function GET(req: NextRequest, { params }: { params: { provider: string } }) {
  const code = req.nextUrl.searchParams.get('code')!;

  // Step 3: Exchange code for tokens
  const tokenRes = await fetch(PROVIDERS[params.provider].tokenUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
    body: JSON.stringify({
      client_id: PROVIDERS[params.provider].clientId,
      client_secret: PROVIDERS[params.provider].clientSecret,
      code,
      redirect_uri: `${BASE_URL}/api/auth/callback/${params.provider}`,
    }),
  });
  const { access_token } = await tokenRes.json();

  // Step 4: Get user info
  const userRes = await fetch(PROVIDERS[params.provider].userUrl, {
    headers: { Authorization: `Bearer ${access_token}` },
  });
  const profile = await userRes.json();

  // Create/update user + session
  const user = await upsertUser(profile);
  await createSession(user.id);
  return redirect('/dashboard');
}
